# Retry rejected e-invoices for companies with auto_submit enabled. configs = env['mumtaz.einvoice.config'].search([('auto_submit', '=', True)]) auto_submit_company_ids = configs.mapped('company_id').ids
rejected_moves = env['account.move'].search([ ('einvoice_status', '=', 'rejected'), ('state', '=', 'posted'), ('move_type', 'in', ['out_invoice', 'out_refund']), ('company_id', 'in', auto_submit_company_ids), ])
for move in rejected_moves: try: move.action_submit_einvoice() env.cr.commit() except Exception as e: env.cr.rollback() import logging logging.getLogger(__name__).warning( 'E-invoice retry failed for %s: %s', move.name, e )
